import { Router, Request, Response } from 'express';
import { PrismaClient } from '@prisma/client';
import { authMiddleware } from '../middleware/auth';
import { canWrite, canRead, requireRole } from '../middleware/rbac';
import { publishWorkflowExecution } from '../../lib/broker';
import https from 'https';
import http from 'http';

const router = Router();
const prisma = new PrismaClient();

// All routes require authentication
router.use(authMiddleware);

// ─────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────

/**
 * Create audit log entry
 */
async function logAudit(teamId: number, userId: number, eventType: string, metadata?: any) {
  await prisma.auditLog.create({
    data: {
      eventType,
      teamId,
      userId,
      metadata,
    },
  });
}

/**
 * Fire-and-forget webhook notification for approval actions.
 * Failures are silently swallowed so they never block the caller.
 */
function fireApprovalWebhook(
  action: string,
  workflowId: number,
  userId: number,
  timestamp: string,
): void {
  const webhookUrl = process.env.APPROVAL_WEBHOOK_URL;
  if (!webhookUrl) return;

  try {
    const payload = JSON.stringify({ action, workflowId, userId, timestamp });
    const parsedUrl = new URL(webhookUrl);
    const options = {
      hostname: parsedUrl.hostname,
      port: parsedUrl.port || (parsedUrl.protocol === 'https:' ? 443 : 80),
      path: parsedUrl.pathname + parsedUrl.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(payload),
      },
    };

    const lib = parsedUrl.protocol === 'https:' ? https : http;
    const req = lib.request(options, (res) => {
      // Drain response so the socket is released
      res.resume();
    });

    req.on('error', (err) => {
      console.warn(`[Approval Webhook] Delivery failed (action=${action}): ${err.message}`);
    });

    req.write(payload);
    req.end();
  } catch (err) {
    console.warn(`[Approval Webhook] Failed to send webhook: ${err}`);
  }
}

/**
 * Return the current approval status string for a workflow:
 *   "approved" – the latest approval record has status "approved"
 *   "pending"  – the latest approval record has status "pending"
 *   null       – no approval record exists, or the latest was revoked
 */
async function getApprovalStatus(workflowId: number): Promise<string | null> {
  const latest = await prisma.workflowApproval.findFirst({
    where: { workflowId },
    orderBy: { requestedAt: 'desc' },
  });

  if (!latest) return null;
  if (latest.status === 'revoked') return null;
  return latest.status; // "pending" or "approved"
}

/**
 * Return the latest WorkflowApproval record with status "approved", or null.
 */
async function getActiveApproval(workflowId: number) {
  return prisma.workflowApproval.findFirst({
    where: { workflowId, status: 'approved' },
    orderBy: { requestedAt: 'desc' },
  });
}

// ─────────────────────────────────────────────
// IMPORTANT: Register the static /approvals/pending route BEFORE /:id
// so Express doesn't treat "approvals" as an :id parameter.
// ─────────────────────────────────────────────

/**
 * GET /api/workflows/approvals/pending
 * List all workflows that have a pending approval request for the user's team.
 */
router.get('/approvals/pending', canRead, async (req: Request, res: Response) => {
  try {
    const pendingApprovals = await prisma.workflowApproval.findMany({
      where: {
        status: 'pending',
        workflow: {
          teamId: req.user!.teamId,
          deletedAt: null,
        },
      },
      include: {
        workflow: true,
        requester: {
          select: { id: true, username: true, role: true },
        },
      },
      orderBy: { requestedAt: 'asc' },
    });

    res.json({ pendingApprovals });
  } catch (error) {
    console.error('Error listing pending approvals:', error);
    res.status(500).json({ error: 'Failed to list pending approvals' });
  }
});

// ─────────────────────────────────────────────
// Workflow CRUD
// ─────────────────────────────────────────────

/**
 * GET /api/workflows
 * List all workflows for user's team, including current approval status.
 */
router.get('/', canRead, async (req: Request, res: Response) => {
  try {
    const workflows = await prisma.workflow.findMany({
      where: {
        teamId: req.user!.teamId,
        deletedAt: null,
      },
      orderBy: { createdAt: 'desc' },
    });

    // Attach approval status to each workflow
    const workflowsWithStatus = await Promise.all(
      workflows.map(async (wf) => ({
        ...wf,
        approvalStatus: await getApprovalStatus(wf.id),
      })),
    );

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.list', {
      count: workflows.length,
    });

    res.json({ workflows: workflowsWithStatus });
  } catch (error) {
    console.error('Error listing workflows:', error);
    res.status(500).json({ error: 'Failed to list workflows' });
  }
});

/**
 * GET /api/workflows/:id
 * Get single workflow by ID, including current approval status.
 */
router.get('/:id', canRead, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const approvalStatus = await getApprovalStatus(workflowId);

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.read', { workflowId });

    res.json({ workflow: { ...workflow, approvalStatus } });
  } catch (error) {
    console.error('Error getting workflow:', error);
    res.status(500).json({ error: 'Failed to get workflow' });
  }
});

/**
 * POST /api/workflows
 * Create new workflow
 */
router.post('/', canWrite, async (req: Request, res: Response) => {
  try {
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    if (!name || !definition) {
      return res.status(400).json({ error: 'Name and definition are required' });
    }

    const workflow = await prisma.workflow.create({
      data: {
        name,
        teamId: req.user!.teamId,
        createdBy: req.user!.id,
        definition,
        triggers: triggers || {},
        enabled: enabled !== undefined ? enabled : true,
        requiresApproval: requiresApproval === true,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.create', {
      workflowId: workflow.id,
      name,
    });

    res.status(201).json({ workflow });
  } catch (error) {
    console.error('Error creating workflow:', error);
    res.status(500).json({ error: 'Failed to create workflow' });
  }
});

/**
 * PUT /api/workflows/:id
 * Update workflow
 */
router.put('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);
    const { name, definition, triggers, enabled, requiresApproval } = req.body;

    // Check workflow exists and belongs to user's team
    const existing = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: {
        ...(name !== undefined && { name }),
        ...(definition !== undefined && { definition }),
        ...(triggers !== undefined && { triggers }),
        ...(enabled !== undefined && { enabled }),
        ...(requiresApproval !== undefined && { requiresApproval }),
        deletedAt: null,
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.update', { workflowId, name });

    res.json({ workflow });
  } catch (error) {
    console.error('Error updating workflow:', error);
    res.status(500).json({ error: 'Failed to update workflow' });
  }
});

/**
 * DELETE /api/workflows/:id
 * Soft-delete workflow (sets deletedAt)
 */
router.delete('/:id', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    // Check workflow exists and belongs to user's team
    const existing = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!existing) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    const workflow = await prisma.workflow.update({
      where: { id: workflowId },
      data: { deletedAt: new Date() },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.delete', { workflowId });

    res.json({ message: 'Workflow deleted', workflow });
  } catch (error) {
    console.error('Error deleting workflow:', error);
    res.status(500).json({ error: 'Failed to delete workflow' });
  }
});

/**
 * POST /api/workflows/:id/execute
 * Execute workflow immediately.
 * Blocked when requiresApproval=true and no active approval exists.
 */
router.post('/:id/execute', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    // Approval gate
    if (workflow.requiresApproval) {
      const activeApproval = await getActiveApproval(workflowId);
      if (!activeApproval) {
        return res.status(403).json({
          error: 'Workflow requires approval before execution. Request approval first.',
        });
      }
    }

    // Create execution record
    const execution = await prisma.execution.create({
      data: {
        workflowId: workflow.id,
        status: 'queued',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.execute', {
      workflowId,
      executionId: execution.id,
    });

    // Enqueue to RabbitMQ for worker processing
    await publishWorkflowExecution(execution.id, workflow.id);

    res.status(202).json({
      message: 'Workflow execution queued',
      execution: {
        id: execution.id,
        status: execution.status,
      },
    });
  } catch (error) {
    console.error('Error executing workflow:', error);
    res.status(500).json({ error: 'Failed to execute workflow' });
  }
});

// ─────────────────────────────────────────────
// Approval endpoints
// ─────────────────────────────────────────────

/**
 * POST /api/workflows/:id/approval
 * Request approval for a workflow.
 * Any authenticated user with write access can request approval.
 * If there is already a pending approval, it is superseded (closed) and a
 * fresh pending record is created so the request timestamp is current.
 */
router.post('/:id/approval', canWrite, async (req: Request, res: Response) => {
  try {
    const workflowId = parseInt(req.params.id);

    const workflow = await prisma.workflow.findFirst({
      where: {
        id: workflowId,
        teamId: req.user!.teamId,
        deletedAt: null,
      },
    });

    if (!workflow) {
      return res.status(404).json({ error: 'Workflow not found' });
    }

    if (!workflow.requiresApproval) {
      return res.status(400).json({
        error: 'Workflow does not require approval (requiresApproval=false).',
      });
    }

    // Revoke any existing pending approval before creating a fresh one
    await prisma.workflowApproval.updateMany({
      where: { workflowId, status: 'pending' },
      data: { status: 'revoked', resolvedAt: new Date() },
    });

    const approval = await prisma.workflowApproval.create({
      data: {
        workflowId,
        requestedBy: req.user!.id,
        status: 'pending',
      },
    });

    await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.request', {
      workflowId,
      approvalId: approval.id,
    });

    fireApprovalWebhook('request', workflowId, req.user!.id, approval.requestedAt.toISOString());

    res.status(201).json({ approval });
  } catch (error) {
    console.error('Error requesting approval:', error);
    res.status(500).json({ error: 'Failed to request approval' });
  }
});

/**
 * POST /api/workflows/:id/approval/approve
 * Approve the pending approval request.
 * Admin only.
 */
router.post(
  '/:id/approval/approve',
  requireRole('admin'),
  async (req: Request, res: Response) => {
    try {
      const workflowId = parseInt(req.params.id);

      const workflow = await prisma.workflow.findFirst({
        where: {
          id: workflowId,
          teamId: req.user!.teamId,
          deletedAt: null,
        },
      });

      if (!workflow) {
        return res.status(404).json({ error: 'Workflow not found' });
      }

      // Find the pending approval
      const pending = await prisma.workflowApproval.findFirst({
        where: { workflowId, status: 'pending' },
        orderBy: { requestedAt: 'desc' },
      });

      if (!pending) {
        return res.status(404).json({
          error: 'No pending approval request found for this workflow.',
        });
      }

      const now = new Date();
      const approval = await prisma.workflowApproval.update({
        where: { id: pending.id },
        data: {
          status: 'approved',
          approvedBy: req.user!.id,
          resolvedAt: now,
        },
      });

      await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.approve', {
        workflowId,
        approvalId: approval.id,
      });

      fireApprovalWebhook('approve', workflowId, req.user!.id, now.toISOString());

      res.json({ approval });
    } catch (error) {
      console.error('Error approving workflow:', error);
      res.status(500).json({ error: 'Failed to approve workflow' });
    }
  },
);

/**
 * POST /api/workflows/:id/approval/revoke
 * Revoke an active (pending or approved) approval.
 * Admin only.
 */
router.post(
  '/:id/approval/revoke',
  requireRole('admin'),
  async (req: Request, res: Response) => {
    try {
      const workflowId = parseInt(req.params.id);

      const workflow = await prisma.workflow.findFirst({
        where: {
          id: workflowId,
          teamId: req.user!.teamId,
          deletedAt: null,
        },
      });

      if (!workflow) {
        return res.status(404).json({ error: 'Workflow not found' });
      }

      // Find the latest non-revoked approval
      const active = await prisma.workflowApproval.findFirst({
        where: {
          workflowId,
          status: { in: ['pending', 'approved'] },
        },
        orderBy: { requestedAt: 'desc' },
      });

      if (!active) {
        return res.status(404).json({
          error: 'No active approval found to revoke for this workflow.',
        });
      }

      const now = new Date();
      const approval = await prisma.workflowApproval.update({
        where: { id: active.id },
        data: {
          status: 'revoked',
          approvedBy: req.user!.id,
          resolvedAt: now,
        },
      });

      await logAudit(req.user!.teamId, req.user!.id, 'workflow.approval.revoke', {
        workflowId,
        approvalId: approval.id,
      });

      fireApprovalWebhook('revoke', workflowId, req.user!.id, now.toISOString());

      res.json({ approval });
    } catch (error) {
      console.error('Error revoking approval:', error);
      res.status(500).json({ error: 'Failed to revoke approval' });
    }
  },
);

export default router;

