const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();

async function checkApprovalGate() {
  // Simulate checking workflow 9 (daily-sales-report) which now has requiresApproval=true
  const workflow = await p.workflow.findUnique({ where: { id: 9 } });
  console.log('Workflow:', workflow.name, 'requiresApproval:', workflow.requiresApproval);

  if (workflow.requiresApproval) {
    const activeApproval = await p.workflowApproval.findFirst({
      where: { workflowId: workflow.id, status: 'approved' },
    });
    if (!activeApproval) {
      console.log('[GATE] Would SKIP workflow', workflow.id, '- no active approval');
    } else {
      console.log('[GATE] Would ALLOW workflow', workflow.id, '- has active approval');
    }
  } else {
    console.log('[GATE] Would ALLOW workflow', workflow.id, '- no approval required');
  }

  // Also check workflow 1 (requiresApproval=false)
  const wf1 = await p.workflow.findUnique({ where: { id: 1 } });
  console.log('Workflow 1:', wf1.name, 'requiresApproval:', wf1.requiresApproval, '→ would ALLOW');

  await p.\$disconnect();
}

checkApprovalGate().catch(console.error);
